import{_ as n,o as i,c as a,ag as h}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"[Admin Specs] Sprint 3: Quản trị Tìm kiếm & Khám phá (Search Config)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/05-admin-specs.md","filePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/05-admin-specs.md"}'),o={name:"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/05-admin-specs.md"};function e(r,t,c,u,s,l){return i(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="admin-specs-sprint-3-quan-tri-tim-kiem-kham-pha-search-config" tabindex="-1">[Admin Specs] Sprint 3: Quản trị Tìm kiếm &amp; Khám phá (Search Config) <a class="header-anchor" href="#admin-specs-sprint-3-quan-tri-tim-kiem-kham-pha-search-config" aria-label="Permalink to &quot;[Admin Specs] Sprint 3: Quản trị Tìm kiếm &amp; Khám phá (Search Config)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện Admin dành cho việc cấu hình và quản trị bộ lọc tìm kiếm.</p><h2 id="_1-man-hinh-cap-nhat-featured-noi-bat" tabindex="-1">1. Màn hình Cập nhật &quot;Featured&quot; (Nổi bật) <a class="header-anchor" href="#_1-man-hinh-cap-nhat-featured-noi-bat" aria-label="Permalink to &quot;1. Màn hình Cập nhật &quot;Featured&quot; (Nổi bật)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>SortableList</code> (HeroUI/Dnd-kit).</li><li><strong>Mục tiêu</strong>: Cho phép Admin chọn tối đa 6 Điểm đến và 10 Tour để hiển thị tại Homepage &quot;Featured Sections&quot;.</li><li><strong>Hành động</strong>: Kéo thả (Drag-and-drop) để thay đổi thứ tự hiển thị (<code>sortOrder</code>).</li></ul><h2 id="_2-cau-hinh-hot-search-tu-khoa-pho-bien" tabindex="-1">2. Cấu hình &quot;Hot Search&quot; (Từ khóa phổ biến) <a class="header-anchor" href="#_2-cau-hinh-hot-search-tu-khoa-pho-bien" aria-label="Permalink to &quot;2. Cấu hình &quot;Hot Search&quot; (Từ khóa phổ biến)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>InputTags</code>.</li><li><strong>Mục tiêu</strong>: Nhập danh sách các từ khóa mà hệ thống sẽ gợi ý ngay khi người dùng chưa nhập gì vào ô Search (e.g. &quot;Vịnh Hạ Long&quot;, &quot;Phú Quốc&quot;, &quot;Tour giá rẻ&quot;).</li><li><strong>Hành động</strong>: Thêm/Xóa tags từ khóa.</li></ul><h2 id="_3-quan-ly-loai-hinh-du-lich-tour-categories" tabindex="-1">3. Quản lý Loại hình Du lịch (Tour Categories) <a class="header-anchor" href="#_3-quan-ly-loai-hinh-du-lich-tour-categories" aria-label="Permalink to &quot;3. Quản lý Loại hình Du lịch (Tour Categories)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Table</code> (CRUD Category).</li><li><strong>Columns</strong>: Tên (Vi/En), Icon (Lucide icon name), Trạng thái.</li><li><strong>Mục đích</strong>: Cung cấp dữ liệu cho bộ lọc &quot;Loại hình&quot; (e.g. Du lịch tâm linh, Mạo hiểm, Nghỉ dưỡng).</li></ul><h2 id="_4-đac-ta-quy-trinh-admin-flows" tabindex="-1">4. Đặc tả Quy trình (Admin Flows) <a class="header-anchor" href="#_4-đac-ta-quy-trinh-admin-flows" aria-label="Permalink to &quot;4. Đặc tả Quy trình (Admin Flows)&quot;">​</a></h2><ul><li><strong>Analytics View</strong>: Admin xem biểu đồ &quot;Từ khóa được tìm kiếm nhiều nhất&quot; (Search queries log) để điều chỉnh kế hoạch marketing.</li><li><strong>Filter Refresh</strong>: Sau khi Admin cập nhật Category, hệ thống tự động xóa cache (Purge Cache) cho bộ lọc ngoài Client.</li></ul><hr><p><em>Tài liệu đặc tả Admin cho Sprint 3.</em></p>',12)])])}const p=n(o,[["render",e]]);export{d as __pageData,p as default};
